package dao;

import config.HibernateUtil;
import model.Account;
import org.hibernate.Session;
import org.hibernate.LockMode;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.math.BigDecimal;

public class AccountDao {
    private static final Logger log = LoggerFactory.getLogger(AccountDao.class);

    public Account findById(Long id) {
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            return session.get(Account.class, id);
        }
    }

    public Account findByIdWithLock(Long id, Session session) {
        return session.get(Account.class, id, LockMode.PESSIMISTIC_WRITE);
    }

    public void updateBalance(Account account, Session session) {
        session.update(account);
    }

    public boolean hasSufficientBalance(Long accountId, BigDecimal amount) {
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Account account = session.get(Account.class, accountId);
            return account != null && account.getBalance().compareTo(amount) >= 0;
        }
    }
}

package dao;

import config.HibernateUtil;
import model.Account;
import org.hibernate.Session;
import org.hibernate.LockMode;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.math.BigDecimal;

public class AccountDao {
    private static final Logger log = LoggerFactory.getLogger(AccountDao.class);

    public Account findById(Long id) {
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            return session.get(Account.class, id);
        }
    }

    public Account findByIdWithLock(Long id, Session session) {
        return session.get(Account.class, id, LockMode.PESSIMISTIC_WRITE);
    }

    public void updateBalance(Account account, Session session) {
        session.merge(account);
    }

    public boolean hasSufficientBalance(Long accountId, BigDecimal amount) {
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            Account account = session.get(Account.class, accountId);
            return account != null && account.getCurrentBalance().compareTo(amount) >= 0;
        }
    }
}

package config;

import org.hibernate.SessionFactory;
