package config;

import model.Account;
import model.MoneyTransfer;
import org.hibernate.HibernateException;
import org.hibernate.SessionFactory;
import org.hibernate.boot.registry.StandardServiceRegistryBuilder;
import org.hibernate.cfg.Configuration;
import org.hibernate.service.ServiceRegistry;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class HibernateUtil {
    private static SessionFactory sessionFactory;
    private static final Logger log = LoggerFactory.getLogger(HibernateUtil.class);

    static {
        try {
            sessionFactory = buildSessionFactory();
        } catch (HibernateException e) {
            log.error("Failed to initialize Hibernate SessionFactory", e);
            throw new ExceptionInInitializerError(e);
        }
    }

    private static SessionFactory buildSessionFactory() throws HibernateException {
        try {
            Configuration configuration = new Configuration();

            // Получаем параметры БД из переменных окружения
            String dbHost = System.getenv("DB_HOST");
            String dbPort = System.getenv("DB_PORT");
            String dbName = System.getenv("DB_NAME");
            String dbUser = System.getenv("DB_USER");
            String dbPassword = System.getenv("DB_PASSWORD");

            // Значения по умолчанию для локальной разработки
            if (dbHost == null) dbHost = "localhost";
            if (dbPort == null) dbPort = "5432";
            if (dbName == null) dbName = "bankdb";
            if (dbUser == null) dbUser = "bankuser";
            if (dbPassword == null) dbPassword = "bankpass";

            String jdbcUrl = String.format("jdbc:postgresql://%s:%s/%s", dbHost, dbPort, dbName);

            // Основные настройки подключения к БД
            configuration.setProperty("hibernate.dialect", "org.hibernate.dialect.PostgreSQLDialect");
            configuration.setProperty("hibernate.connection.driver_class", "org.postgresql.Driver");
            configuration.setProperty("hibernate.connection.url", jdbcUrl);
            configuration.setProperty("hibernate.connection.username", dbUser);
            configuration.setProperty("hibernate.connection.password", dbPassword);

            // Настройки пула соединений
            configuration.setProperty("hibernate.hikari.maximumPoolSize", "10");
            configuration.setProperty("hibernate.hikari.minimumIdle", "5");
            configuration.setProperty("hibernate.hikari.connectionTimeout", "20000");
            configuration.setProperty("hibernate.hikari.idleTimeout", "300000");

            // Настройки SQL и логирования
            configuration.setProperty("hibernate.show_sql", "false");
            configuration.setProperty("hibernate.format_sql", "true");
            configuration.setProperty("hibernate.generate_statistics", "false");

            // Настройки транзакций
            configuration.setProperty("hibernate.enable_lazy_load_no_trans", "true");
            configuration.setProperty("hibernate.jdbc.batch_size", "20");
            configuration.setProperty("hibernate.jdbc.fetch_size", "50");

            // Добавляем сущности
            configuration.addAnnotatedClass(Account.class);
            configuration.addAnnotatedClass(MoneyTransfer.class);

            log.info("Hibernate configuration created for database: {}", jdbcUrl);

            // Создаем ServiceRegistry и SessionFactory
            ServiceRegistry serviceRegistry = new StandardServiceRegistryBuilder()
                    .applySettings(configuration.getProperties())
                    .build();

            SessionFactory factory = configuration.buildSessionFactory(serviceRegistry);
            log.info("Hibernate SessionFactory initialized successfully");

            return factory;

        } catch (Throwable ex) {
            log.error("Failed to create SessionFactory", ex);
            throw new ExceptionInInitializerError(ex);
        }
    }

    public static SessionFactory getSessionFactory() {
        return sessionFactory;
    }

    public static void shutdown() {
        if (sessionFactory != null && !sessionFactory.isClosed()) {
            try {
                sessionFactory.close();
                log.info("Hibernate SessionFactory closed successfully");
            } catch (HibernateException e) {
                log.error("Error closing Hibernate SessionFactory", e);
            }
        }
    }
}

package service;

import com.fasterxml.jackson.databind.ObjectMapper;
import config.HibernateUtil;
import dao.AccountDao;
import model.Account;
import model.MoneyTransfer;
import model.TransferStatus;
import org.hibernate.Session;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class TransactionProcessor {
    private static final Logger log = LoggerFactory.getLogger(TransactionProcessor.class);

    private final AccountDao accountDAO;
    private final MoneyTransfer transactionDAO;
    private final ObjectMapper objectMapper;
    private final String consumerId;

    public TransactionProcessor(String consumerId) {
        this.accountDAO = new AccountDao();
        this.transactionDAO = new MoneyTransfer();
        this.objectMapper = new ObjectMapper();
        this.consumerId = consumerId;
    }

    public void processMessage(String messageValue) {
        log.info("Consumer {} started processing message", consumerId);

        try {
            // Десериализуем сообщение
            MoneyTransfer moneyTransfer =
                    objectMapper.readValue(messageValue, MoneyTransfer.class);

            log.info("Processing transaction: {} from {} to {} amount {}",
                    moneyTransfer.getId(),
                    moneyTransfer.getFromAccountId(),
                    moneyTransfer.getToAccountId(),
                    moneyTransfer.getAmount());

            // Валидация счетов
            if (!validateAccounts(moneyTransfer)) {
                log.error("Validation failed for transaction {}", moneyTransfer.getId());
                saveFailedTransaction(moneyTransfer);
                return;
            }

            // Проверка баланса
            if (!checkBalance(moneyTransfer)) {
                log.error("Insufficient balance for transaction {}", moneyTransfer.getId());
                saveFailedTransaction(moneyTransfer);
                return;
            }

            // Выполняем транзакцию БД
            executeTransaction(moneyTransfer);

            log.info("Successfully processed transaction {}", moneyTransfer.getId());

        } catch (Exception e) {
            log.error("Error processing message: {}", e.getMessage(), e);
        }
    }

    private boolean validateAccounts(MoneyTransfer moneyTransfer) {
        Account fromAccount = accountDAO.findById(moneyTransfer.getFromAccountId());
        Account toAccount = accountDAO.findById(moneyTransfer.getToAccountId());

        if (fromAccount == null) {
            log.error("From account {} not found", moneyTransfer.getFromAccountId());
            return false;
        }

        if (toAccount == null) {
            log.error("To account {} not found", moneyTransfer.getToAccountId());
            return false;
        }

        return true;
    }

    private boolean checkBalance(MoneyTransfer moneyTransfer) {
        return accountDAO.hasSufficientBalance(
                moneyTransfer.getFromAccountId(),
                moneyTransfer.getAmount()
        );
    }

    private void executeTransaction(MoneyTransfer moneyTransfer) {
        Session session = null;
        MoneyTransfer hibernateTx = null;

        try {
            session = HibernateUtil.getSessionFactory().openSession();
            hibernateTx = (MoneyTransfer) session.beginTransaction();

            // Блокируем счета для обновления
            Account fromAccount = accountDAO.findByIdWithLock(moneyTransfer.getFromAccountId(), session);
            Account toAccount = accountDAO.findByIdWithLock(moneyTransfer.getToAccountId(), session);

            if (fromAccount == null || toAccount == null) {
                throw new RuntimeException("Accounts not found during transaction");
            }

            // Снимаем деньги
            fromAccount.setBalance(fromAccount.getBalance().subtract(moneyTransfer.getAmount()));
            accountDAO.updateBalance(fromAccount, session);

            // Зачисляем деньги
            toAccount.setBalance(toAccount.getBalance().add(moneyTransfer.getAmount()));
            accountDAO.updateBalance(toAccount, session);

            // Создаем запись о переводе
            MoneyTransfer dbMoneyTransfer = new MoneyTransfer(
                    moneyTransfer.getId(),
                    moneyTransfer.getFromAccountId(),
                    moneyTransfer.getToAccountId(),
                    moneyTransfer.getAmount(),
                    TransferStatus.SUCCESS
            );
            transactionDAO.save(dbMoneyTransfer, session);

            hibernateTx.commit();
            log.info("Database transaction committed successfully for transfer {}",
                    moneyTransfer.getId());

        } catch (Exception e) {
            log.error("Transaction failed, rolling back: {}", e.getMessage());
            if (hibernateTx != null && hibernateTx.isActive()) {
                hibernateTx.rollback();
            }

            // Даже при ошибке сохраняем запись с FAILED статусом
            saveFailedTransactionWithSession(moneyTransfer, session);
        } finally {
            if (session != null && session.isOpen()) {
                session.close();
            }
        }
    }

    private void saveFailedTransaction(MoneyTransfer moneyTransfer) {
        Session session = null;
        org.hibernate.Transaction hibernateTx = null;

        try {
            session = HibernateUtil.getSessionFactory().openSession();
            hibernateTx = session.beginTransaction();

            transactionDAO.saveFailed(
                    moneyTransfer.getId(),
                    moneyTransfer.getFromAccountId(),
                    moneyTransfer.getToAccountId(),
                    moneyTransfer.getAmount(),
                    session
            );

            hibernateTx.commit();

        } catch (Exception e) {
            log.error("Failed to save error transaction: {}", e.getMessage());
            if (hibernateTx != null && hibernateTx.isActive()) {
                hibernateTx.rollback();
            }
        } finally {
            if (session != null && session.isOpen()) {
                session.close();
            }
        }
    }

    private void saveFailedTransactionWithSession(MoneyTransfer moneyTransfer,
                                                  Session session) {
        boolean needCloseSession = false;

        try {
            if (session == null || !session.isOpen()) {
                session = HibernateUtil.getSessionFactory().openSession();
                needCloseSession = true;
            }

            org.hibernate.Transaction hibernateTx = session.getTransaction();
            if (!hibernateTx.isActive()) {
                hibernateTx.begin();
            }

            transactionDAO.saveFailed(
                    moneyTransfer.getId(),
                    moneyTransfer.getFromAccountId(),
                    moneyTransfer.getToAccountId(),
                    moneyTransfer.getAmount(),
                    session
            );

            hibernateTx.commit();
            log.info("Saved failed transaction record for {}", moneyTransfer.getId());

        } catch (Exception e) {
            log.error("Failed to save failed transaction: {}", e.getMessage());
        } finally {
            if (needCloseSession && session != null && session.isOpen()) {
                session.close();
            }
        }
    }
}

